import{c as i,Q as a,j as l,m as t}from"./chunks/framework.DVkeSyfh.js";const h=JSON.parse('{"title":"Обзор","description":"","frontmatter":{},"headers":[],"relativePath":"ru/overview.md","filePath":"ru/overview.md","lastUpdated":1780017810000}'),r={name:"ru/overview.md"};function o(s,e,d,c,p,n){return a(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="обзор" tabindex="-1">Обзор <a class="header-anchor" href="#обзор" aria-label="Permalink to &quot;Обзор&quot;">​</a></h1><p>Эта страница объясняет, что такое <code>dj-track-similarity</code>, что он делает и какие границы безопасности применяются к обычным рабочим процессам приложения. Прочитайте ее первой, если решаете, подходит ли проект для вашей локальной DJ-библиотеки.</p><h2 id="обзор-проекта" tabindex="-1">Обзор проекта <a class="header-anchor" href="#обзор-проекта" aria-label="Permalink to &quot;Обзор проекта&quot;">​</a></h2><p><code>dj-track-similarity</code> - локальный инструмент анализа музыкальной библиотеки для подготовки DJ-сетов. Он сканирует папку с аудиофайлами, сохраняет метаданные и результаты анализа в SQLite и помогает искать треки, которые могут хорошо работать рядом друг с другом в сете.</p><p>Это персональный энтузиастский инструмент, а не коммерческий продукт и не формальный benchmark для audio research. Практическая цель - упростить просмотр, тегирование, поиск и подготовку реальной локальной коллекции к DJ использованию.</p><p>У приложения две основные поверхности:</p><ul><li>Python backend и CLI, устанавливаемый как <code>dj-sim</code>.</li><li>React/Vite frontend, который отдает FastAPI backend.</li></ul><p>Используйте CLI для повторяемых команд, пакетной работы и быстрых проверок. Используйте web UI, когда нужно просматривать библиотеку, слушать, сравнивать кандидатов, настраивать поиск, экспортировать временный сет или проверять метаданные перед действием.</p><h2 id="типичныи-рабочии-процесс" tabindex="-1">Типичный рабочий процесс <a class="header-anchor" href="#типичныи-рабочии-процесс" aria-label="Permalink to &quot;Типичный рабочий процесс&quot;">​</a></h2><p>Обычный путь через приложение:</p><ol><li>Выбрать или создать SQLite-базу.</li><li>Просканировать музыкальную папку.</li><li>Запустить один или несколько проходов анализа: Sonara, MAEST, MERT или CLAP.</li><li>Просматривать постраничную библиотеку, смотреть метаданные треков и выбирать seed-треки.</li><li>Искать через SONARA, MERT или CLAP.</li><li>Собрать временный сет и экспортировать его как M3U или CSV.</li><li>При необходимости оценить треки продвинутыми classifier profiles.</li><li>При необходимости записать MAEST-жанры в стандартные genre tags аудиофайлов.</li></ol><p>Не нужно запускать все семейства анализа. Практичная отправная точка:</p><ul><li>Сначала выполните <code>scan</code>, чтобы библиотека появилась в SQLite.</li><li>Запускайте Sonara, когда нужны быстрый объяснимый similarity search и фильтры по признакам библиотеки.</li><li>Запускайте MAEST, когда нужны сгенерированные жанры или preset <code>syncopated</code>.</li><li>Запускайте MERT, когда нужна audio similarity от seed-треков через embeddings.</li><li>Запускайте CLAP, когда нужны текстовые prompts вроде &quot;dark hypnotic techno&quot;.</li><li>Запускайте продвинутые классификаторы только после появления данных Sonara, MERT и MAEST для треков, которые нужно оценить.</li></ul><h2 id="ключевые-возможности" tabindex="-1">Ключевые возможности <a class="header-anchor" href="#ключевые-возможности" aria-label="Permalink to &quot;Ключевые возможности&quot;">​</a></h2><ul><li>Сканирует локальные аудиопапки и сохраняет строки треков в SQLite.</li><li>Читает фиксированный whitelist человеко-понятных Mutagen-тегов.</li><li>Обновляет Mutagen-теги уже индексированных треков без удаления анализа.</li><li>Переносит сохраненные пути треков после перемещения той же папки библиотеки.</li><li>Извлекает Sonara playlist features для ритма, громкости, тональности, perceptual и spectral inspection.</li><li>Строит MERT audio embeddings для поиска похожести по seed-трекам.</li><li>Строит CLAP audio embeddings и CLAP text vectors для text-to-audio search.</li><li>Извлекает MAEST genre labels и confidence scores.</li><li>Сохраняет MAEST embeddings во время genre analysis.</li><li>Оценивает продвинутые classifier models по существующим данным SONARA, MERT и MAEST.</li><li>Хранит статус анализа по трекам для <code>sonara</code>, <code>maest</code>, <code>mert</code> и <code>clap</code>.</li><li>Хранит classifier scores отдельно от file tags и model metadata.</li><li>Держит browser библиотеки server-side paginated для больших локальных коллекций.</li><li>Загружает полные метаданные одного трека только при открытии metadata dialog.</li><li>Отдает browser previews, запускает playback по кнопке preview и транскодирует AIFF/AIF во временные seekable WAV-файлы.</li><li>Экспортирует текущий временный сет как <code>.m3u</code> или <code>.csv</code>.</li><li>Сбрасывает семейства анализа независимо в SQLite.</li><li>Очищает локальную базу после явного подтверждения.</li><li>Записывает стандартные genre tags из сохраненных MAEST labels только по явному запросу.</li></ul><h2 id="модель-безопасности" tabindex="-1">Модель безопасности <a class="header-anchor" href="#модель-безопасности" aria-label="Permalink to &quot;Модель безопасности&quot;">​</a></h2><p>Стандартное поведение приложения - database-first и read-only для аудиофайлов.</p><ul><li>Сканирование читает файлы и пишет только строки SQLite.</li><li>RefreshTags перечитывает file metadata и пишет только строки SQLite.</li><li>Анализ Sonara, MAEST, MERT и CLAP читает аудио и пишет только результаты анализа в SQLite.</li><li>Продвинутая classifier scoring читает существующие данные анализа SQLite и пишет только classifier rows SQLite. Он не декодирует и не изменяет аудио.</li><li>Поиск читает SQLite и не меняет ни аудио, ни базу.</li><li>Browser preview отдает аудио для player; AIFF/AIF previews могут транскодироваться через <code>ffmpeg</code> во временные seekable WAV-файлы, но исходные файлы не перезаписываются.</li><li>Export пишет только playlist/export файлы.</li><li>Analysis reset удаляет только выбранные локальные SQLite outputs анализа.</li><li>Database clear удаляет только локальные SQLite track rows, embedding rows и зависимые classifier-score rows.</li><li>Library relocation обновляет только сохраненные значения <code>tracks.path</code> в SQLite.</li></ul><p>Явное исключение - workflow сохранения жанров:</p><ul><li><code>/api/tags/genres/apply</code> и <code>/api/tags/genres/jobs</code> могут записывать стандартные audio genre tags из сохраненных MAEST labels.</li><li>Запись жанров должна перезаписывать только поле genre.</li><li>Существующие title, artist, album, BPM, key и другие обычные tags должны остаться нетронутыми.</li></ul><p>Отдельный helper <code>scripts/audio_repair/repair_audio_metadata.py</code> - еще одно явное исключение. Он отделен от приложения, по умолчанию работает в dry-run и может перезаписывать repairable аудиофайлы только с <code>--apply</code>.</p><h2 id="поддерживаемые-аудиофаилы" tabindex="-1">Поддерживаемые аудиофайлы <a class="header-anchor" href="#поддерживаемые-аудиофаилы" aria-label="Permalink to &quot;Поддерживаемые аудиофайлы&quot;">​</a></h2><p>Основной scanner сейчас индексирует такие расширения:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.aif, .aiff, .alac, .flac, .m4a, .mp3, .ogg, .opus, .wav, .wave</span></span></code></pre></div><p>Repair helper поддерживает более широкий diagnostic set, потому что проверяет несоответствия контейнера и codec для большего числа форматов. См. <a href="./scripts/repair-audio-metadata.html">скрипт восстановления аудиометаданных</a> для этого workflow.</p>',25)])])}const m=i(r,[["render",o]]);export{h as __pageData,m as default};
